UPDATE words SET example_en_2 = 'Subrogation allows the insurer to sue the at-fault party.', example_ko_2 = '대위권은 보험사가 과실 있는 당사자를 소송할 수 있게 해요.', example_en_3 = 'The insurer waived its subrogation rights in the agreement.', example_ko_3 = '보험사가 계약서에서 대위권을 포기했어요.', example_en_4 = 'Subrogation prevents the insured from recovering twice.', example_ko_4 = '대위권은 피보험자가 이중으로 보상받는 것을 방지해요.', example_en_5 = 'The concept of subrogation is central to insurance law.', example_ko_5 = '대위의 개념은 보험법의 핵심이에요.' WHERE id = 'w_work_C2_34';

UPDATE words SET example_en_2 = 'The acquisition is expected to be accretive to earnings per share.', example_ko_2 = '인수가 주당 순이익에 긍정적으로 작용할 것으로 예상돼요.', example_en_3 = 'Accretion of the discount increased the bond''s book value.', example_ko_3 = '할인액 가산으로 채권의 장부 가치가 증가했어요.', example_en_4 = 'Management described the deal as immediately accretive.', example_ko_4 = '경영진이 거래가 즉각적으로 이익 증가 효과가 있다고 설명했어요.', example_en_5 = 'Accretion schedules are prepared for each debt instrument.', example_ko_5 = '각 부채 상품에 대한 가산 일정이 작성돼요.' WHERE id = 'w_work_C2_35';
